def _coerce_list_of_dicts(
    values: Any,
    fields: list[str],
    limit: int,
    aliases: dict[str, tuple[str, ...]] | None = None,
) -> list[dict[str, Any]]:
    if values is None:
        return []
    if isinstance(values, dict):
        values = [values]
    if not isinstance(values, (list, tuple, set)):
        return []

    aliases = aliases or {}
    out: list[dict[str, Any]] = []
    for value in values:
        if not isinstance(value, dict):
            continue
        row: dict[str, Any] = {}
        for field in fields:
            raw = value.get(field)
            if raw is None:
                for alias in aliases.get(field, ()):
